function Section({eyebrow,title,desc,action}:{eyebrow:string;title:string;desc?:string;action?:React.ReactNode}){return <div className="flex flex-col gap-4 md:flex-row md:items-end md:justify-between"><div><p className="text-xs font-black uppercase tracking-[0.25em] text-sky-600">{eyebrow}</p><h2 className="mt-2 text-2xl font-black tracking-tight text-slate-950 md:text-3xl">{title}</h2>{desc?<p className="mt-2 max-w-3xl text-sm font-semibold leading-6 text-slate-600">{desc}</p>:null}</div>{action?<div className="flex flex-wrap gap-2">{action}</div>:null}</div>}
function Header({mode,title}:{mode:Mode;title:string}){return <section className="rounded-[2rem] border border-slate-900 bg-white p-6 text-slate-950 shadow-2xl shadow-slate-200 lg:p-8"><div className="flex flex-wrap gap-2"><Badge kind="dark">SEO Blog</Badge><span className="rounded-full border border-slate-200 bg-white/10 px-3 py-1 text-xs font-black uppercase tracking-widest text-slate-950">{label(mode)}</span></div><h1 className="mt-5 max-w-5xl text-4xl font-black tracking-tight text-slate-950 md:text-5xl">{title}</h1><p className="mt-4 max-w-4xl text-base font-semibold leading-8 text-slate-700">A focused senior SEO workspace with direct forms, controls, decisions and storage synchronization. No decorative dead cards.</p><div className="mt-6 flex flex-wrap gap-3"><Button href="/market-os/seo-blog-workspace" kind="dark">Back to SEO command</Button><Button href="/market-os/seo-blog-workspace/create" kind="primary">+ Create article</Button><Button href="/market-os/seo-blog-workspace/calendar" kind="dark">Calendar</Button></div></section>}
