const emptyArticle: SeoArticle = { id:"", title:"", slug:"", status:"idea", priority:"Medium", channel:"Blog", owner:"", reviewer:"", cluster:"", primaryKeyword:"", secondaryKeywords:[], intent:"informational", audience:"", objective:"", metaTitle:"", metaDescription:"", h1:"", outline:[], body:"", internalLinks:[], externalLinks:[], brandScore:75, seoScore:70, readability:80, dueDate:todayISO(7), scheduledDate:todayISO(14), createdAt:"", updatedAt:"", notes:"", canonicalUrl:"", wordCount:0, impressions:0, clicks:0, rank:99, conversions:0 }

function SubpagePlaybookPanel(){return <Panel className="p-5"><Section eyebrow="Workflow intelligence" title="Subpage execution playbook" desc="This workspace includes embedded workflow checkpoints for senior SEO execution. Showing the most relevant slice only, while keeping the playbook available in code."/><div className="mt-5 grid gap-3 md:grid-cols-2 xl:grid-cols-4">{SUBPAGE_EXECUTION_PLAYBOOK.slice(0,8).map(x=><div key={x.id} className="rounded-2xl border border-slate-200 bg-slate-50 p-4"><p className="text-xs font-black uppercase tracking-wider text-sky-600">{x.id}</p><h3 className="mt-2 text-sm font-black text-slate-950">{x.title}</h3><p className="mt-2 text-xs font-bold leading-5 text-slate-9500">{x.managerUse}</p></div>)}</div></Panel>}

function ArticleForm({initial,onSave,submitLabel}:{initial?:SeoArticle; onSave:(a:SeoArticle)=>void; submitLabel:string}){ const [form,setForm]=React.useState<SeoArticle>(initial||emptyArticle); const set=(k:keyof SeoArticle,v:any)=>setForm(f=>({...f,[k]:v})); const save=()=>{ const now=new Date().toISOString(); const next={...form,id:form.id||uid("seo"),slug:form.slug||form.title.toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,""),createdAt:form.createdAt||now,updatedAt:now, secondaryKeywords:typeof form.secondaryKeywords==="string"?(form.secondaryKeywords as any).split(",").map((x:string)=>x.trim()).filter(Boolean):form.secondaryKeywords, outline:typeof form.outline==="string"?(form.outline as any).split("\n").map((x:string)=>x.trim()).filter(Boolean):form.outline, internalLinks:typeof form.internalLinks==="string"?(form.internalLinks as any).split(",").map((x:string)=>x.trim()).filter(Boolean):form.internalLinks}; onSave(next)}; return <Panel className="p-5"><Section eyebrow="SEO production form" title="Article configuration" desc="Fill the operational fields needed for SEO, brand, review and publishing."/><div className="mt-5 grid gap-4 md:grid-cols-2 xl:grid-cols-3"><Field label="Title"><input className={inputClass} value={form.title} onChange={e=>set("title",e.target.value)}/></Field><Field label="Slug"><input className={inputClass} value={form.slug} onChange={e=>set("slug",e.target.value)}/></Field><Field label="Primary keyword"><input className={inputClass} value={form.primaryKeyword} onChange={e=>set("primaryKeyword",e.target.value)}/></Field><Field label="Channel"><select className={inputClass} value={form.channel} onChange={e=>set("channel",e.target.value)}>{channels.map(c=><option key={c}>{c}</option>)}</select></Field><Field label="Status"><select className={inputClass} value={form.status} onChange={e=>set("status",e.target.value)}>{[...statuses,"archived"].map(s=><option key={s} value={s}>{label(s)}</option>)}</select></Field><Field label="Priority"><select className={inputClass} value={form.priority} onChange={e=>set("priority",e.target.value)}>{priorities.map(p=><option key={p}>{p}</option>)}</select></Field><Field label="Search intent"><select className={inputClass} value={form.intent} onChange={e=>set("intent",e.target.value)}>{intents.map(i=><option key={i}>{label(i)}</option>)}</select></Field><Field label="Owner"><input className={inputClass} value={form.owner} onChange={e=>set("owner",e.target.value)}/></Field><Field label="Reviewer"><input className={inputClass} value={form.reviewer} onChange={e=>set("reviewer",e.target.value)}/></Field><Field label="Cluster"><input className={inputClass} value={form.cluster} onChange={e=>set("cluster",e.target.value)}/></Field><Field label="Due date"><input type="date" className={inputClass} value={form.dueDate} onChange={e=>set("dueDate",e.target.value)}/></Field><Field label="Scheduled date"><input type="date" className={inputClass} value={form.scheduledDate} onChange={e=>set("scheduledDate",e.target.value)}/></Field><Field label="SEO score"><input type="number" className={inputClass} value={form.seoScore} onChange={e=>set("seoScore",Number(e.target.value))}/></Field><Field label="Brand score"><input type="number" className={inputClass} value={form.brandScore} onChange={e=>set("brandScore",Number(e.target.value))}/></Field><Field label="Readability"><input type="number" className={inputClass} value={form.readability} onChange={e=>set("readability",Number(e.target.value))}/></Field></div><div className="mt-4 grid gap-4 md:grid-cols-2"><Field label="Meta title"><input className={inputClass} value={form.metaTitle} onChange={e=>set("metaTitle",e.target.value)}/></Field><Field label="Meta description"><textarea className={inputClass} rows={3} value={form.metaDescription} onChange={e=>set("metaDescription",e.target.value)}/></Field><Field label="Audience"><textarea className={inputClass} rows={3} value={form.audience} onChange={e=>set("audience",e.target.value)}/></Field><Field label="Objective"><textarea className={inputClass} rows={3} value={form.objective} onChange={e=>set("objective",e.target.value)}/></Field><Field label="Outline, one line per section"><textarea className={inputClass} rows={6} value={Array.isArray(form.outline)?form.outline.join("\n"):form.outline as any} onChange={e=>set("outline",e.target.value as any)}/></Field><Field label="Body"><textarea className={inputClass} rows={6} value={form.body} onChange={e=>set("body",e.target.value)}/></Field><Field label="Internal links, comma separated"><input className={inputClass} value={Array.isArray(form.internalLinks)?form.internalLinks.join(", "):form.internalLinks as any} onChange={e=>set("internalLinks",e.target.value as any)}/></Field><Field label="Secondary keywords, comma separated"><input className={inputClass} value={Array.isArray(form.secondaryKeywords)?form.secondaryKeywords.join(", "):form.secondaryKeywords as any} onChange={e=>set("secondaryKeywords",e.target.value as any)}/></Field></div><div className="mt-5 flex flex-wrap gap-3"><Button onClick={save} kind="primary">{submitLabel}</Button><Button href="/market-os/seo-blog-workspace">Cancel</Button></div></Panel> }
function ArticlePicker({articles}:{articles:SeoArticle[]}){return <Panel className="p-5"><Section eyebrow="Article list" title="Available SEO articles" desc="Open any article or use this list to understand shared store state."/><div className="mt-5 space-y-3">{articles.map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="flex flex-wrap items-center justify-between gap-3"><div><Link href={`/market-os/seo-blog-workspace/${a.id}`} className="font-black text-slate-950 hover:underline">{a.title}</Link><p className="mt-1 text-xs font-bold text-slate-9500">{a.primaryKeyword} • {a.cluster}</p></div><div className="flex gap-2"><Badge>{label(a.status)}</Badge><Button href={`/market-os/seo-blog-workspace/${a.id}/edit`}>Edit</Button></div></div></div>)}</div></Panel>}
function MonthCalendar({articles,onDate}:{articles:SeoArticle[]; onDate:(iso:string)=>void}){const d=new Date(),y=d.getFullYear(),m=d.getMonth(); const start=new Date(y,m,1).getDay(); const days=new Date(y,m+1,0).getDate(); const cells=Array.from({length:42},(_,i)=>{const day=i-start+1; const date=new Date(y,m,day); const iso=date.toISOString().slice(0,10); return {i,day,iso,inMonth:day>=1&&day<=days}}); return <Panel className="p-5"><Section eyebrow="Monthly calendar" title="SEO editorial calendar" desc="Click a day to create a scheduled article. Open items directly from the grid."/><div className="mt-5 grid grid-cols-7 gap-2 text-center text-xs font-black uppercase text-slate-500">{["Sun","Mon","Tue","Wed","Thu","Fri","Sat"].map(x=><div key={x}>{x}</div>)}</div><div className="mt-2 grid grid-cols-7 gap-2">{cells.map(c=>{const list=articles.filter(a=>a.scheduledDate===c.iso); return <div key={c.i} className={cx("min-h-[150px] rounded-2xl border p-3",c.inMonth?"border-slate-200 bg-white":"border-slate-100 bg-slate-50 text-slate-600")}><button onClick={()=>c.inMonth&&onDate(c.iso)} className="text-left text-sm font-black">{c.inMonth?c.day:""}</button><div className="mt-2 space-y-1">{list.map(a=><Link key={a.id} href={`/market-os/seo-blog-workspace/${a.id}`} className="block rounded-xl bg-white px-2 py-1 text-[11px] font-black text-slate-950">{a.title}</Link>)}</div></div>})}</div></Panel>}

export function SeoSubpage({mode,articleId}:{mode:Mode;articleId?:string}){const {store,commit}=useSeoStore(); const article=store.articles.find(a=>a.id===articleId)||store.articles[0]; const save=(a:SeoArticle)=>commit(d=>{const exists=d.articles.some(x=>x.id===a.id); d.articles=exists?d.articles.map(x=>x.id===a.id?a:x):[a,...d.articles]},mode==="create"?"create":"save",`${mode==="create"?"Created":"Saved"} ${a.title}`); const del=(id:string)=>commit(d=>{d.articles=d.articles.filter(a=>a.id!==id); d.tasks=d.tasks.filter(t=>t.articleId!==id)},"delete",`Deleted article ${id}`); const advance=(id:string)=>commit(d=>{d.articles=d.articles.map(a=>a.id===id?{...a,status:nextStatus(a.status),updatedAt:new Date().toISOString()}:a)},"advance",`Advanced article ${id}`); return <Shell><main data-market-os-root className="mx-auto max-w-[1700px] space-y-6 p-4 lg:p-8"><Header mode={mode} title={mode==="create"?"Create SEO article":mode==="edit"?"Edit SEO article":mode==="delete"?"Delete SEO article":mode==="calendar"?"Monthly SEO calendar":mode==="review"?"SEO review queue":mode==="publishing"?"Publishing desk":mode==="optimizer"?"Article optimizer":mode==="clusters"?"Topic cluster command":mode==="analytics"?"Organic analytics":mode==="brand"?"Brand governance":mode==="linking"?"Internal linking workspace":"SEO article command room"}/><SubpagePlaybookPanel/>{mode==="create"?<ArticleForm onSave={save} submitLabel="Save article"/>:null}{mode==="edit"&&article?<ArticleForm initial={article} onSave={save} submitLabel="Update article"/>:null}{mode==="delete"&&article?<Panel className="p-5"><Section eyebrow="Delete confirmation" title={`Delete ${article.title}?`} desc="This removes the article and connected tasks from the local SEO store."/><div className="mt-5 flex gap-3"><Button onClick={()=>del(article.id)} kind="danger">Confirm delete</Button><Button href="/market-os/seo-blog-workspace">Cancel</Button></div></Panel>:null}{mode==="detail"&&article?<div className="grid gap-5 xl:grid-cols-[1fr_.5fr]"><Panel className="p-5"><Section eyebrow="Article command room" title={article.title} desc={article.objective} action={<><Button href={`/market-os/seo-blog-workspace/${article.id}/edit`} kind="primary">Edit</Button><Button href={`/market-os/seo-blog-workspace/${article.id}/delete`} kind="danger">Delete</Button><Button onClick={()=>advance(article.id)} kind="dark">Move next</Button></>}/><div className="mt-5 grid gap-4 md:grid-cols-3"><div className="rounded-2xl bg-slate-50 p-4"><p className="text-xs font-black uppercase text-slate-500">Keyword</p><p className="mt-2 font-black text-slate-950">{article.primaryKeyword}</p></div><div className="rounded-2xl bg-slate-50 p-4"><p className="text-xs font-black uppercase text-slate-500">SEO score</p><p className="mt-2 font-black text-slate-950">{article.seoScore}</p></div><div className="rounded-2xl bg-slate-50 p-4"><p className="text-xs font-black uppercase text-slate-500">Brand score</p><p className="mt-2 font-black text-slate-950">{article.brandScore}</p></div></div><div className="mt-5 rounded-2xl bg-slate-50 p-5"><h3 className="font-black text-slate-950">Outline</h3><ul className="mt-3 list-disc pl-5 text-sm font-semibold leading-7 text-slate-600">{article.outline.map(x=><li key={x}>{x}</li>)}</ul></div></Panel><Panel className="p-5"><Section eyebrow="Readiness" title="Publish gate"/><div className="mt-5"><Meter value={articleReadiness(article,store.tasks,store.rules)}/><p className="mt-2 text-sm font-black text-slate-600">Readiness {Math.round(articleReadiness(article,store.tasks,store.rules))}%</p><p className={cx("mt-4 rounded-2xl border p-4 text-sm font-black",canPublish(article,store.tasks,store.rules)?"border-emerald-200 bg-emerald-50 text-emerald-700":"border-amber-200 bg-amber-50 text-amber-700")}>{canPublish(article,store.tasks,store.rules)?"Ready to publish":"Not ready to publish"}</p></div></Panel></div>:null}{mode==="calendar"?<MonthCalendar articles={store.articles} onDate={(iso)=>{const a={...emptyArticle,id:uid("seo"),title:`SEO article scheduled ${iso}`,slug:`seo-article-${iso}`,scheduledDate:iso,dueDate:iso,owner:"SEO Lead",reviewer:"Brand Lead",primaryKeyword:"",cluster:"Planning",createdAt:new Date().toISOString(),updatedAt:new Date().toISOString()}; save(a)}}/>:null}{mode==="review"?<Panel className="p-5"><Section eyebrow="Review queue" title="Approve, reject or revise SEO work" desc="Each action updates the shared store."/><div className="mt-5 space-y-3">{store.articles.filter(a=>["draft","review"].includes(a.status)).map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="flex flex-wrap justify-between gap-3"><div><h3 className="font-black text-slate-950">{a.title}</h3><p className="text-xs font-bold text-slate-9500">SEO {a.seoScore} • Brand {a.brandScore}</p></div><div className="flex gap-2"><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,status:"approved"}:x)},"approve",`Approved ${a.title}`)} kind="success">Approve</Button><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,status:"draft",notes:x.notes+"\nRevision requested"}:x)},"revision",`Revision requested for ${a.title}`)}>Revision</Button></div></div></div>)}</div></Panel>:null}{mode==="publishing"?<Panel className="p-5"><Section eyebrow="Publishing desk" title="Schedule, publish or hold approved articles"/><div className="mt-5 space-y-3">{store.articles.filter(a=>["approved","scheduled"].includes(a.status)).map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="flex flex-wrap justify-between gap-3"><div><h3 className="font-black text-slate-950">{a.title}</h3><p className="text-xs font-bold text-slate-9500">Scheduled {a.scheduledDate}</p></div><div className="flex gap-2"><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,status:"published",publishedDate:todayISO()}:x)},"publish",`Published ${a.title}`)} kind="success">Publish now</Button><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,status:"scheduled"}:x)},"schedule",`Scheduled ${a.title}`)}>Schedule</Button></div></div></div>)}</div></Panel>:null}{mode==="optimizer"?<Panel className="p-5"><Section eyebrow="Optimizer" title="Improve SEO and brand scores" desc="Quick controls for score tuning and readiness."/><div className="mt-5 space-y-3">{store.articles.map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="flex flex-wrap justify-between gap-3"><div><h3 className="font-black text-slate-950">{a.title}</h3><p className="text-xs font-bold text-slate-9500">SEO {a.seoScore} • Brand {a.brandScore} • Readability {a.readability}</p></div><div className="flex gap-2"><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,seoScore:Math.min(100,x.seoScore+5),brandScore:Math.min(100,x.brandScore+3),readability:Math.min(100,x.readability+2)}:x)},"optimize",`Optimized ${a.title}`)} kind="primary">Apply improvement</Button><Button href={`/market-os/seo-blog-workspace/${a.id}/edit`}>Edit</Button></div></div></div>)}</div></Panel>:null}{mode==="clusters"?<Panel className="p-5"><Section eyebrow="Topic clusters" title="Organic domination map" desc="Manage clusters, pillars and content expansion."/><div className="mt-5 grid gap-4 md:grid-cols-3">{store.clusters.map(c=><div key={c.id} className="rounded-3xl border border-slate-200 bg-white p-5"><Badge>{c.status}</Badge><h3 className="mt-3 text-xl font-black text-slate-950">{c.name}</h3><p className="mt-2 text-sm font-semibold text-slate-600">{c.target}</p><Button onClick={()=>commit(d=>{d.clusters=d.clusters.map(x=>x.id===c.id?{...x,status:x.status==="active"?"expanding":"active"}:x)},"cluster",`Updated cluster ${c.name}`)} >Toggle status</Button></div>)}</div></Panel>:null}{mode==="analytics"?<Panel className="p-5"><Section eyebrow="Analytics" title="Organic performance view" desc="Ranking, clicks, impressions and conversion impact."/><div className="mt-5 space-y-3">{store.articles.map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="grid gap-3 md:grid-cols-5"><b>{a.title}</b><span>Rank #{a.rank}</span><span>{a.impressions} impressions</span><span>{a.clicks} clicks</span><span>{a.conversions} conversions</span></div></div>)}</div></Panel>:null}{mode==="brand"?<Panel className="p-5"><Section eyebrow="Brand governance" title="Rules, medical sensitivity and CTA discipline"/><div className="mt-5 space-y-3">{store.rules.map(r=><div key={r.id} className="rounded-2xl border border-slate-200 bg-white p-4"><div className="flex justify-between"><div><h3 className="font-black text-slate-950">{r.title}</h3><p className="text-sm font-semibold text-slate-600">{r.description}</p></div><Button onClick={()=>commit(d=>{d.rules=d.rules.map(x=>x.id===r.id?{...x,active:!x.active}:x)},"rule",`Toggled ${r.title}`)}>{r.active?"Disable":"Enable"}</Button></div></div>)}</div></Panel>:null}{mode==="linking"?<Panel className="p-5"><Section eyebrow="Internal linking" title="Authority flow planner" desc="Add internal links to improve cluster strength."/><div className="mt-5 space-y-3">{store.articles.map(a=><div key={a.id} className="rounded-2xl border border-slate-200 bg-white p-4"><h3 className="font-black text-slate-950">{a.title}</h3><p className="mt-1 text-xs font-bold text-slate-9500">Links: {a.internalLinks.join(", ")||"none"}</p><div className="mt-3 flex gap-2"><Button onClick={()=>commit(d=>{d.articles=d.articles.map(x=>x.id===a.id?{...x,internalLinks:[...x.internalLinks,`/market-os/seo-blog-workspace/${x.slug}`]}:x)},"link",`Added internal link to ${a.title}`)} kind="primary">Add suggested link</Button><Button href={`/market-os/seo-blog-workspace/${a.id}/edit`}>Edit links</Button></div></div>)}</div></Panel>:null}<ArticlePicker articles={store.articles}/></main></Shell>}
